var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"울지, 마렴...","JPN":"泣か、ないで……","ENG":"Don't... cry…","TWN":"不要…哭……"},"stage":{"bg":"HARMONY2_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"우리 딸...","JPN":"私の娘……","ENG":"My beloved daughter…","TWN":"我的女兒……"},"stage":{"bg":"HARMONY2_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"허억...!","JPN":"はあっ……！","ENG":"*Gasp...!*","TWN":"哈啊……！"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"하아... 하...","JPN":"はあ……はあ……","ENG":"*Huff...* *Huff...*","TWN":"哈啊……哈……"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"괜찮니, 아가?","JPN":"大丈夫かい？　レア。","ENG":"Are you all right, my dear?","TWN":"沒事吧，孩子？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"엄마...?!","JPN":"お母さん……！？","ENG":"Mom...?","TWN":"媽媽……？！"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"레아 씨...?","JPN":"レアさん……？","ENG":"Leah...?","TWN":"蕾亞……？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"...괜찮아요?","JPN":"……大丈夫ですか？","ENG":"...Are you okay?","TWN":"……你還好嗎？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"크리스? 무슨 일이야, 이 시간에.","JPN":"クリス？　どうしたの、こんな時間に。","ENG":"Chris? What are you doing up at this hour?","TWN":"克莉絲？這麼晚怎麼了？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"숨 넘어가는 소리가 들려서요. 해도 중천이고요.","JPN":"あ、苦しそうな呼吸が聞こえて。","ENG":"Oh, I heard you gasping.","TWN":"啊，我聽到你好像快喘不過氣的聲音。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"미안. 알잖아. 나 맨날 그러는 거.","JPN":"ごめん。でも知ってるでしょ。いつものことだよ。","ENG":"Sorry. You know how it is. I'm always like this.","TWN":"抱歉，你也知道我常這樣。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"또... 그 악몽이죠? ","JPN":"また……あの悪夢ですか？","ENG":"Was it... that nightmare again?","TWN":"又是……那個惡夢嗎？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그건 악몽이 아니야, 크리스.","JPN":"あれは悪夢じゃないよ、クリス。","ENG":"It's not a nightmare, Chris.","TWN":"那不是惡夢，克莉絲。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"내 손으로 만든 현실이지. 엄마는 그렇게 죽었어. 그 사실은 변하지 않아.","JPN":"私の手で作った現実。お母さんはそうやって死んだ。その事実は変わらない。","ENG":"It's a reality I created with my own hands. That's how my mother died. That truth doesn't change.","TWN":"那是我親手造就的現實。媽媽就是那樣死去的，這件事不會改變。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"네퀴티아잖아요. 그런 짓을 한 건 당신이 아니라고요.","JPN":"ネキティアですよ。それをやったのはあなたじゃありません。","ENG":"It was Nequitia. You weren't the one who did it.","TWN":"那是莉奎蒂亞做的，不是你的錯。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...그렇겠지.","JPN":"……だろうね。","ENG":"...Maybe.","TWN":"……也許吧。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"하지만 이 죄를 안고 살아가는 건, 내 나름의 복수이기도 해.","JPN":"でもこの罪を背負って生きるのは、自分なりの復讐でもあるの。","ENG":"But living with that guilt is my way of taking revenge.","TWN":"但背負這份罪活下去，也是我自己的復仇。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아픔을 잊지 않는 게... 어떻게 복수가 된다는 거죠?","JPN":"痛みを忘れないことが……どうして復讐になるんですか？","ENG":"How does refusing to forget the pain... become revenge?","TWN":"不忘記痛苦……怎麼會是復仇呢？"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"내가 그 현실을 어쩔 수 없는 것이라 부정하거나 잊어버리면, 네퀴티아도 그걸 잊게 될 테니까.","JPN":"私があの現実を「仕方ない」と否定したり忘れたりしたら、ネキティアもそれを忘れるだろうから。","ENG":"Because if I deny it or forget it as something unavoidable, then Nequitia would forget it too.","TWN":"如果我把那件事當作無可奈何而選擇遺忘，那莉奎蒂亞也會忘記這一切。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아.......","JPN":"あ……","ENG":"Oh...","TWN":"啊……"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"난 알아. 이 녀석도... 그 순간을 떠올릴 때마다 괴로워하는 게, 느껴지거든.","JPN":"私には分かる。こいつも……あの瞬間を思い出すたびに苦しむのが、伝わってくるんだ。","ENG":"I can tell. Every time that moment comes back to me... it hurts her too.","TWN":"我知道。那傢伙……每次想起那一刻，都感到痛苦。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"일어났사옵니까?","JPN":"お目覚めですか？","ENG":"Did you rest well?","TWN":"你醒了嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"에클레시아?","JPN":"エクレシア？","ENG":"Ecclesia?","TWN":"艾可露西亞？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"주방에서 또 요리하고 있던 거야?","JPN":"うちのキッチンでまた料理をしてたの？","ENG":"You were cooking in my kitchen again?","TWN":"你又在我廚房做料理？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"예!","JPN":"はい！","ENG":"Yes!","TWN":"對！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...또 감자 요리네.","JPN":"……またジャガイモ料理だね。","ENG":"...Potatoes again.","TWN":"……又是馬鈴薯料理。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그렇지요. 분명 맛있을 것이옵...","JPN":"そうです。きっと美味しいはず……","ENG":"Indeed. Surely it shall be del—","TWN":"是的，一定很好吃……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"...혹, 드시기 싫은 것이옵니까?","JPN":"……ひょっとして、あまり食べたくないのですか？","ENG":"...Do you not wish to eat it?","TWN":"……啊，你不想吃嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};